@* Displays a single task card with move-left/move-right buttons *@

<div class="task-card">
    <div class="task-header">
        <span class="task-title">@Task.Title</span>
        <span class="priority-badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    </div>
    <div class="task-meta">
        <span class="task-assignee">👤 @Task.Assignee</span>
        <span class="task-due">📅 @Task.DueDate.ToString("MMM dd")</span>
    </div>
    <div class="task-actions">
        @if (ShowMoveLeft)
        {
            <button class="btn btn-sm btn-move" @onclick="() => OnMoveLeft.InvokeAsync(Task.Id)" disabled="@IsMoving">
                ◀ Move Left
            </button>
        }
        @if (ShowMoveRight)
        {
            <button class="btn btn-sm btn-move" @onclick="() => OnMoveRight.InvokeAsync(Task.Id)" disabled="@IsMoving">
                Move Right ▶
            </button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public bool IsMoving { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }
}

@* Inline form for creating a new task within a column *@

<div class="add-task-form">
    <div class="form-group">
        <input type="text" class="form-control" placeholder="Title" @bind="title" />
    </div>
    <div class="form-group">
        <input type="text" class="form-control" placeholder="Assignee" @bind="assignee" />
    </div>
    <div class="form-group">
        <select class="form-control" @bind="priority">
            <option value="">-- Priority --</option>
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
    </div>
    <div class="form-group">
        <input type="date" class="form-control" @bind="dueDate" />
    </div>
    <div class="form-actions">
        <button class="btn btn-save" @onclick="HandleSave" disabled="@isSaving">
            @(isSaving ? "Saving..." : "Save")
        </button>
        <button class="btn btn-cancel" @onclick="HandleCancel" disabled="@isSaving">Cancel</button>
    </div>
    @if (!string.IsNullOrEmpty(validationError))
    {
        <div class="form-error">@validationError</div>
    }
</div>

@code {
    [Parameter, EditorRequired] public string ColumnStatus { get; set; } = default!;
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = string.Empty;
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;
    private string? validationError;

    [Inject] private ITaskService TaskService { get; set; } = default!;

    private async Task HandleSave()
    {
        validationError = null;

        if (string.IsNullOrWhiteSpace(title) || string.IsNullOrWhiteSpace(assignee) || string.IsNullOrWhiteSpace(priority))
        {
            validationError = "Title, assignee, and priority are required.";
            return;
        }

        isSaving = true;
        try
        {
            var created = await TaskService.CreateTaskAsync(title, assignee, priority, dueDate);
            await OnTaskCreated.InvokeAsync(created);
            ResetForm();
        }
        catch (Exception ex)
        {
            validationError = $"Failed to create task: {ex.Message}";
        }
        finally
        {
            isSaving = false;
        }
    }

    private async Task HandleCancel()
    {
        ResetForm();
        await OnCancel.InvokeAsync();
    }

    private void ResetForm()
    {
        title = string.Empty;
        assignee = string.Empty;
        priority = string.Empty;
        dueDate = DateTime.Today.AddDays(7);
        validationError = null;
    }
}

@* Search bar for filtering tasks by title *@

<div class="board-search">
    <input type="text"
           class="form-control search-input"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = string.Empty;
    [Parameter] public EventCallback<string> OnSearchChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? string.Empty);
    }
}

@* A single Kanban column displaying its tasks and an add-task form *@

<div class="board-column">
    <div class="column-header">
        <h3>@ColumnName</h3>
        <span class="column-count">@Tasks.Count</span>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      IsMoving="movingTaskId == task.Id"
                      OnMoveLeft="HandleMoveLeft"
                      OnMoveRight="HandleMoveRight" />
        }
    </div>

    <div class="column-footer">
        @if (showAddForm)
        {
            <AddTaskForm ColumnStatus="@ColumnName"
                         OnTaskCreated="HandleTaskCreated"
                         OnCancel="() => showAddForm = false" />
        }
        else
        {
            <button class="btn btn-add-task" @onclick="() => showAddForm = true">+ Add Task</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = default!;
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = [];
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<(int TaskId, string Direction)> OnTaskMoved { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool showAddForm;
    private int? movingTaskId;

    private async Task HandleMoveLeft(int taskId)
    {
        movingTaskId = taskId;
        try
        {
            await OnTaskMoved.InvokeAsync((taskId, "left"));
        }
        finally
        {
            movingTaskId = null;
        }
    }

    private async Task HandleMoveRight(int taskId)
    {
        movingTaskId = taskId;
        try
        {
            await OnTaskMoved.InvokeAsync((taskId, "right"));
        }
        finally
        {
            movingTaskId = null;
        }
    }

    private async Task HandleTaskCreated(TaskItem task)
    {
        showAddForm = false;
        await OnTaskCreated.InvokeAsync(task);
    }
}

