@page "/board"
@rendermode InteractiveServer
@using sv_3760512f8ec340c6b49bfc6e37817f7a.Components.Pages.Board
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<div class="board-page">
    <h1>Kanban Board</h1>

    @if (isLoading)
    {
        <div class="board-loading">Loading tasks...</div>
    }
    else if (errorMessage is not null)
    {
        <div class="board-error">
            <p>@errorMessage</p>
            <button class="btn" @onclick="LoadTasks">Retry</button>
        </div>
    }
    else
    {
        <BoardStats Tasks="allTasks" />

        <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

        <div class="board-columns">
            <BoardColumn ColumnName="To Do"
                         Tasks="GetFilteredTasksForStatus(\"To Do\")"
                         ShowMoveLeft="false"
                         ShowMoveRight="true"
                         OnTaskMoved="HandleTaskMoved"
                         OnTaskCreated="HandleTaskCreated" />

            <BoardColumn ColumnName="In Progress"
                         Tasks="GetFilteredTasksForStatus(\"In Progress\")"
                         ShowMoveLeft="true"
                         ShowMoveRight="true"
                         OnTaskMoved="HandleTaskMoved"
                         OnTaskCreated="HandleTaskCreated" />

            <BoardColumn ColumnName="Done"
                         Tasks="GetFilteredTasksForStatus(\"Done\")"
                         ShowMoveLeft="true"
                         ShowMoveRight="false"
                         OnTaskMoved="HandleTaskMoved"
                         OnTaskCreated="HandleTaskCreated" />
        </div>
    }
</div>

@code {
    private static readonly string[] Columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = [];
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasksForStatus(string status)
    {
        var query = allTasks.Where(t => t.Status == status);

        if (!string.IsNullOrWhiteSpace(searchText))
        {
            query = query.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private async Task HandleTaskMoved((int TaskId, string Direction) move)
    {
        var task = allTasks.FirstOrDefault(t => t.Id == move.TaskId);
        if (task is null) return;

        var currentIndex = Array.IndexOf(Columns, task.Status);
        var newIndex = move.Direction == "left" ? currentIndex - 1 : currentIndex + 1;

        if (newIndex < 0 || newIndex >= Columns.Length) return;

        var newStatus = Columns[newIndex];

        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            // Update local state: replace old record with updated status
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            allTasks[index] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private Task HandleTaskCreated(TaskItem task)
    {
        allTasks.Add(task);
        return Task.CompletedTask;
    }
}

/* ── Board page layout ── */
.board-page {
    max-width: 1200px;
    margin: 0 auto;
    padding: 1rem;
}

.board-page h1 {
    margin-bottom: 1rem;
}

/* ── Loading & error ── */
.board-loading,
.board-error {
    text-align: center;
    padding: 3rem 1rem;
    font-size: 1.1rem;
}

.board-error {
    color: #dc3545;
}

/* ── Stats bar ── */
.board-stats {
    display: flex;
    gap: 1rem;
    flex-wrap: wrap;
    margin-bottom: 1rem;
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border-radius: 8px;
}

.stat-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    min-width: 70px;
}

.stat-value {
    font-size: 1.5rem;
    font-weight: 700;
}

.stat-label {
    font-size: 0.8rem;
    color: #6c757d;
}

.stat-overdue .stat-value {
    color: #dc3545;
}

/* ── Search bar ── */
.board-search {
    margin-bottom: 1rem;
}

.search-input {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 6px;
    font-size: 0.95rem;
}

/* ── Column layout ── */
.board-columns {
    display: flex;
    gap: 1rem;
}

.board-column {
    flex: 1;
    background: #f1f3f5;
    border-radius: 8px;
    display: flex;
    flex-direction: column;
    min-height: 300px;
}

.column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 1rem;
    border-bottom: 2px solid #dee2e6;
}

.column-header h3 {
    margin: 0;
    font-size: 1rem;
}

.column-count {
    background: #dee2e6;
    border-radius: 999px;
    padding: 0.15rem 0.5rem;
    font-size: 0.85rem;
    font-weight: 600;
}

.column-body {
    flex: 1;
    padding: 0.5rem;
    overflow-y: auto;
}

.column-footer {
    padding: 0.5rem;
}

/* ── Task card ── */
.task-card {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 0.75rem;
    margin-bottom: 0.5rem;
    box-shadow: 0 1px 2px rgba(0,0,0,.06);
}

.task-header {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    margin-bottom: 0.4rem;
}

.task-title {
    font-weight: 600;
    font-size: 0.95rem;
}

.priority-badge {
    font-size: 0.7rem;
    font-weight: 600;
    padding: 0.15rem 0.45rem;
    border-radius: 4px;
    text-transform: uppercase;
}

.priority-high {
    background: #f8d7da;
    color: #842029;
}

.priority-medium {
    background: #fff3cd;
    color: #664d03;
}

.priority-low {
    background: #d1e7dd;
    color: #0f5132;
}

.task-meta {
    display: flex;
    gap: 0.75rem;
    font-size: 0.8rem;
    color: #6c757d;
    margin-bottom: 0.5rem;
}

.task-actions {
    display: flex;
    gap: 0.4rem;
}

/* ── Buttons ── */
.btn {
    border: none;
    cursor: pointer;
    border-radius: 4px;
    padding: 0.35rem 0.65rem;
    font-size: 0.85rem;
    background: #e9ecef;
}

.btn:hover {
    background: #dee2e6;
}

.btn:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

.btn-sm {
    font-size: 0.75rem;
    padding: 0.2rem 0.5rem;
}

.btn-move {
    background: #e2e6ea;
}

.btn-add-task {
    width: 100%;
    background: #e9ecef;
    font-weight: 600;
}

.btn-save {
    background: #0d6efd;
    color: #fff;
}

.btn-save:hover {
    background: #0b5ed7;
}

.btn-cancel {
    background: #e9ecef;
}

/* ── Add-task form ── */
.add-task-form {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 0.75rem;
}

.form-group {
    margin-bottom: 0.5rem;
}

.form-control {
    width: 100%;
    padding: 0.35rem 0.5rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 0.85rem;
    box-sizing: border-box;
}

.form-actions {
    display: flex;
    gap: 0.4rem;
}

.form-error {
    margin-top: 0.4rem;
    color: #dc3545;
    font-size: 0.8rem;
}

