@page "/board"
@rendermode InteractiveServer
@using sv_3760512f8ec340c6b49bfc6e37817f7a.Components.Pages.Board
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<div class="board-page">
    <h1>Kanban Board</h1>

    @if (isLoading)
    {
        <div class="board-loading">Loading tasks...</div>
    }
    else if (errorMessage is not null)
    {
        <div class="board-error">
            <p>@errorMessage</p>
            <button class="btn" @onclick="LoadTasks">Retry</button>
        </div>
    }
    else
    {
        <BoardStats Tasks="allTasks" />

        <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

        <div class="board-columns">
            <BoardColumn ColumnName="To Do"
                         Tasks="GetFilteredTasksForStatus(\"To Do\")"
                         ShowMoveLeft="false"
                         ShowMoveRight="true"
                         OnTaskMoved="HandleTaskMoved"
                         OnTaskCreated="HandleTaskCreated" />

            <BoardColumn ColumnName="In Progress"
                         Tasks="GetFilteredTasksForStatus(\"In Progress\")"
                         ShowMoveLeft="true"
                         ShowMoveRight="true"
                         OnTaskMoved="HandleTaskMoved"
                         OnTaskCreated="HandleTaskCreated" />

            <BoardColumn ColumnName="Done"
                         Tasks="GetFilteredTasksForStatus(\"Done\")"
                         ShowMoveLeft="true"
                         ShowMoveRight="false"
                         OnTaskMoved="HandleTaskMoved"
                         OnTaskCreated="HandleTaskCreated" />
        </div>
    }
</div>

@code {
    private static readonly string[] Columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = [];
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasksForStatus(string status)
    {
        var query = allTasks.Where(t => t.Status == status);

        if (!string.IsNullOrWhiteSpace(searchText))
        {
            query = query.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private async Task HandleTaskMoved((int TaskId, string Direction) move)
    {
        var task = allTasks.FirstOrDefault(t => t.Id == move.TaskId);
        if (task is null) return;

        var currentIndex = Array.IndexOf(Columns, task.Status);
        var newIndex = move.Direction == "left" ? currentIndex - 1 : currentIndex + 1;

        if (newIndex < 0 || newIndex >= Columns.Length) return;

        var newStatus = Columns[newIndex];

        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            // Update local state: replace old record with updated status
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            allTasks[index] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private Task HandleTaskCreated(TaskItem task)
    {
        allTasks.Add(task);
        return Task.CompletedTask;
    }
}

