/* ── Board page layout ── */
.board-page {
    max-width: 1200px;
    margin: 0 auto;
    padding: 1rem;
}

.board-page h1 {
    margin-bottom: 1rem;
}

/* ── Loading & error ── */
.board-loading,
.board-error {
    text-align: center;
    padding: 3rem 1rem;
    font-size: 1.1rem;
}

.board-error {
    color: #dc3545;
}

/* ── Stats bar ── */
.board-stats {
    display: flex;
    gap: 1rem;
    flex-wrap: wrap;
    margin-bottom: 1rem;
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border-radius: 8px;
}

.stat-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    min-width: 70px;
}

.stat-value {
    font-size: 1.5rem;
    font-weight: 700;
}

.stat-label {
    font-size: 0.8rem;
    color: #6c757d;
}

.stat-overdue .stat-value {
    color: #dc3545;
}

/* ── Search bar ── */
.board-search {
    margin-bottom: 1rem;
}

